def extract_tar_file(archive_path, destination_dir):
    # Validate inputs
    if not os.path.exists(archive_path):
        raise ValueError("Archive file does not exist")
    
    if not os.path.isdir(destination_dir):
        raise ValueError("Destination directory does not exist")
    
    # Validate archive path is within allowed scope
    archive_path = os.path.abspath(archive_path)
    destination_dir = os.path.abspath(destination_dir)
    
    # Allowlist of valid archive extensions
    valid_extensions = ['.tar', '.tar.gz', '.tgz', '.tar.bz2', '.tbz2']
    if not any(archive_path.endswith(ext) for ext in valid_extensions):
        raise ValueError("Invalid archive extension")
    
    # Allowlist of valid tar commands
    tar_commands = ['x', 'xf', 'xzf', 'xjf']
    
    # Extract the archive
    try:
        subprocess.run(['tar', '-xf', archive_path, '-C', destination_dir], 
                      check=True, shell=False, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to extract archive: {e.stderr.decode()}")

def convert_file_with_libreoffice(input_file, output_format, output_dir):
    # Validate inputs
    if not os.path.exists(input_file):
        raise ValueError("Input file does not exist")
    
    # Validate output directory
    if not os.path.isdir(output_dir):
        raise ValueError("Output directory does not exist")
    
    # Allowlist of valid output formats
    valid_formats = ['pdf', 'docx', 'odt', 'html', 'txt']
    if output_format not in valid_formats:
        raise ValueError(f"Invalid output format. Must be one of: {valid_formats}")
    
    # Get input file extension
    input_ext = os.path.splitext(input_file)[1][1:].lower()
    
    # Validate input file extension
    valid_input_formats = ['odt', 'doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx', 'txt', 'rtf']
    if input_ext not in valid_input_formats:
        raise ValueError(f"Invalid input file format. Must be one of: {valid_input_formats}")
    
    # Generate output filename
    input_name = os.path.splitext(os.path.basename(input_file))[0]
    output_file = os.path.join(output_dir, f"{input_name}.{output_format}")
    
    # Convert using libreoffice
    try:
        subprocess.run(['libreoffice', '--headless', '--convert-to', output_format, 
                       '--outdir', output_dir, input_file], 
                      check=True, shell=False, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to convert file: {e.stderr.decode()}")